def passes(q, exp, n):
    ctx = get_legal_context(q, collections=["laws", "case_law"], n_results=n)
    titles = re.findall(r'\[(?:Законы и НПА|Судебная практика)\] — ([^\n]+)', ctx)
    return any(re.search(exp, t, re.I) for t in titles), [t[:46] for t in titles]

def run(n):
    a_ok = c_ok = both = phrase = retr = anom = 0
    K1 = []; K23 = []; ANOM = []
    for topic, aq, cq, exp in PAIRS:
        ap, at = passes(aq, exp, n)
        cp, ct = passes(cq, exp, n)
        a_ok += ap; c_ok += cp
        if ap and cp: both += 1
        elif ap and not cp: phrase += 1; K1.append((topic, cq, ct))
        elif not ap and not cp: retr += 1; K23.append((topic, aq, at, cq, ct))
        else: anom += 1; ANOM.append((topic, aq))
    N = len(PAIRS)
    print(f"\n{'='*72}\n###### ПАРНЫЙ EVAL (top-{n}), тем: {N} ######", flush=True)
    print(f"  Академические:  {a_ok}/{N} = {100*a_ok/N:.0f}%   ← ПОТОЛОК НАХОДИМОСТИ", flush=True)
    print(f"  Разговорные:    {c_ok}/{N} = {100*c_ok/N:.0f}%", flush=True)
    print(f"  Устойчивость к формулировке (разг✓ среди академ✓): {100*both/max(a_ok,1):.0f}%", flush=True)
    print(f"  --- раскладка пар ---", flush=True)
    print(f"  оба ✓:                       {both}", flush=True)
    print(f"  КОРЕНЬ 1 (академ✓ разг✗):    {phrase}  ← query rewriting", flush=True)
    print(f"  КОРЕНЬ 2/3 (оба ✗):          {retr}  ← находимость (лексика/корпус)", flush=True)
    print(f"  аномалия (академ✗ разг✓):    {anom}", flush=True)
    if K1:
        print(f"\n  === КОРЕНЬ 1 — мост формулировки (находится академически, теряется разговорно) ===", flush=True)
        for topic, cq, ct in K1:
            print(f"   • [{topic}] «{cq}»", flush=True)
    if K23:
        print(f"\n  === КОРЕНЬ 2/3 — НЕ находится даже академически (находимость/корпус) ===", flush=True)
        for topic, aq, at, cq, ct in K23:
            print(f"   • [{topic}] академ: «{aq[:60]}»", flush=True)
            print(f"        вернулось: {at}", flush=True)
    if ANOM:
        print(f"\n  === аномалии (академ✗ разг✓) ===", flush=True)
        for topic, aq in ANOM:
            print(f"   • [{topic}] «{aq[:60]}»", flush=True)

if __name__ == "__main__":
    for n in (3, 5):
        run(n)
